//******************************************************************************************************************************
// All the data is readily available in Stocks table
// You can run a query by placing the cursor anywhere on the query text and clicking the run button (or Shift + Enter).
// KQL overview https://aka.ms/KQL_overview
// Quick KQL reference guide can be found here https://aka.ms/kql-quick-reference
//******************************************************************************************************************************

// Let's start with basic data analysis 

// Check the count of records in 'Stocks' table
Stocks 
| count

// When did we start capturing the stock data and what is the maximum date?
Stocks
| summarize min(Date), max(Date)
// Observation: stocks are captured from 1983 to 2022

// What is the record count for each Stock?
Stocks
| summarize count() by Ticker
// Observation: Most of the stocks have an average of 10K records

// Let's extract some deeper insights

// Consider a gaming company like "Activision Blizzard" and sort it's yearly performance over the years
Stocks
| where Ticker == "ATVI"                                            // Stock symbol for 'Activision Blizzard' is ATVI
| summarize max(Close), min(Close) by startofyear(Date)             // Aggregating closing stock prices per year
| extend YearlyPercentChange = round((max_Close - min_Close)/ min_Close *100,2)     // Yearly jump percentage
| order by YearlyPercentChange
// Observation: 1995 was the biggest change for Activision with 351.79% jump

// Render a timechart for S&P 500 index
Stocks
| where Ticker == "^GSPC"   // Stock Symbol for S&P 500 index
| project Close, Date
| order by Date asc 
| render timechart 
// Observation: If we invested in 1 stock of S&P 500 at inception @ 138, the value of that stock would be 3839. That's a whopping 2700% growth

// Render a timechart for 'Microsoft' stock with its average closing price
Stocks
| where Ticker == "MSFT"                     // Stock symbol for Microsoft stock
| summarize avg(Close) by startofyear(Date)  // round all the dates to 'start of the year' date and calculate average
| render timechart 
// Observation 1: Microsoft had a bull run starting 2014 and peaked in 2013 at 275.9
// Observation 2: Compare this timechart with above timechart. Notice how startofyear() function has smoothed the chart.

// Find the top 100 days which saw a huge downfall percentage in market i.e., Market crashed 
Stocks
| where Ticker == "^GSPC"                               // Considering top 500 stocks with S&P 500 index
| serialize 
| extend prevClose = prev(Close,1)                      
| extend PercentChange = round((prevClose - Close)/ Close *100,2) // Calculate % change of current day closing price with previous closing price
| top 100 by PercentChange                                      // only the top 100 highest percentage changes            
| project Date, PercentChange
| render scatterchart 
// Observation 1: Oct 19 , 1987 was the highest ever % downfall in market famously referred to as 'Black Monday'
// Observation 2: Highest concentration of crashes is in 2008 Sep to Dec famously referred to as 'Global Financial Crisis'

// Top 3 stocks had the biggest ever fall in any given year? 
Stocks
| summarize max(Close), min(Close) by Ticker, startofyear(Date)
| extend PercentChange = round((max_Close - min_Close)/ min_Close *100,2)
| top 3 by PercentChange
// Observation 1: Booking Holdings, SBA Communication and American International Group have seen highest % change of price in a year
// Observation 2: AIG (American International Group) seems to be affected around 2008. Let's find out next.

// Checking on some stocks that were impacted by 2008 crash
Stocks
| where Ticker == "AIG"
| project Close, Date
| order by Date asc 
| render timechart 
// Observation: "Falling Giant: A Case Study of AIG" AIG saw a major downfall in 2008 and almost went into a state of bankruptcy

// Let's also check top 5 stocks with highest overall growth
Stocks
| summarize max(Close), min(Close) by Ticker
| extend PercentChange = round((max_Close - min_Close)/ min_Close *100,2)
| top 5 by PercentChange
// Observation: NVR inc, Monster Beverages, United Health Group, Danaher Corp and Amgen inc saw highest growth from 1987 to 2022

// It is worth to look at the trend of growth for the above Stocks
let _top5growthStocks=Stocks
| summarize max(Close), min(Close) by Ticker
| extend PercentChange = round((max_Close - min_Close)/ min_Close *100,2)
| top 5 by PercentChange
| project Ticker;
Stocks
| where Ticker in (_top5growthStocks)
| project Close, Date, Ticker
| order by Date asc 
| render timechart with ( legend=visible)
// Observation: NVR inc, a real estate company takes the trophy for biggest growth since its bull run in 2000 - approx. 46400%
